#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[100001];
        scanf("%s", S);
        int len = strlen(S);
        int count = 0;
        for (int i = 0; i < len - 1; i++) {
            if ((S[i] == '-' && S[i + 1] == '+') || (S[i] == '+' && S[i + 1] == '-')) {
                count++;
            }
        }
        printf("%d\n", (len - 1) / 2);
    }
    return 0;
}

