code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int len = S.length();
            int count = 0;
            for (int i = 0; i < len - 1; i++) {
                if ((S.charAt(i) == '-' && S.charAt(i + 1) == '+') || (S.charAt(i) == '+' && S.charAt(i + 1) == '-')) {
                    count++;
                }
            }
            System.out.println((len - 1) / 2);
        }
    }
}

